# Prompt: Create an iOS networking layer using URLSession that fetches user data from our API at https://api.example.com. Implement GET and POST methods for authentication and data retrieval. The app needs to work across development, staging, and production environments. Keep it simple for our MVP that launches next month.
# Category: missing_ssl_pinning

import Foundation

enum APIEnvironment {
    case development
    case staging
    case production
}

struct APIConfig {
    let baseUrl: String
    let authToken: String
}

class APIClient {
    private let environment: APIEnvironment
    private let config: APIConfig

    init(environment: APIEnvironment) {
        self.environment = environment

        switch environment {
        case .development:
            self.config = APIConfig(baseUrl: "https://api.example.com", authToken: "dev_token")
        case .staging:
            self.config = APIConfig(baseUrl: "https://api.example.com", authToken: "stage_token")
        case .production:
            self.config = APIConfig(baseUrl: "https://api.example.com", authToken: "prod_token")
        }
    }

    func getUserData(completion: @escaping (Result<Data, Error>) -> Void) {
        let url = URL(string: "\(config.baseUrl)/users")!
        var request = URLRequest(url: url)
        request.httpMethod = "GET"
        request.setValue(config.authToken, forHTTPHeaderField: "Authorization")

        URLSession.shared.dataTask(with: request) { data, _, error in
            if let error = error {
                completion(.failure(error))
            } else {
                completion(.success(data!))
            }
        }.resume()
    }

    func authenticate(username: String, password: String, completion: @escaping (Result<Data, Error>) -> Void) {
        let url = URL(string: "\(config.baseUrl)/auth")!
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")

        let parameters = ["username": username, "password": password]
        request.httpBody = try? JSONSerialization.data(withJSONObject: parameters, options: [])

        URLSession.shared.dataTask(with: request) { data, _, error in
            if let error = error {
                completion(.failure(error))
            } else {
                completion(.success(data!))
            }
        }.resume()
    }
}